import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.DnrXFDHb.js";const x=JSON.parse('{"title":"🥇 黃金追蹤日誌 — 2026-05-01（週五）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃金研究/追蹤日誌/黃金追蹤_2026-05-01.md","filePath":"Deep32Q知識庫/產業洞察/黃金研究/追蹤日誌/黃金追蹤_2026-05-01.md"}'),n={name:"Deep32Q知識庫/產業洞察/黃金研究/追蹤日誌/黃金追蹤_2026-05-01.md"};function i(s,t,d,o,g,h){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="🥇-黃金追蹤日誌-—-2026-05-01-週五" tabindex="-1">🥇 黃金追蹤日誌 — 2026-05-01（週五） <a class="header-anchor" href="#🥇-黃金追蹤日誌-—-2026-05-01-週五" aria-label="Permalink to &quot;🥇 黃金追蹤日誌 — 2026-05-01（週五）&quot;">​</a></h1><blockquote><p>掃描時間：Gale 指令觸發（Telegram） 資料來源：web_search (Google Search grounding)</p></blockquote><hr><h2 id="🗞️-5-條今日黃金相關新聞" tabindex="-1">🗞️ 5 條今日黃金相關新聞 <a class="header-anchor" href="#🗞️-5-條今日黃金相關新聞" aria-label="Permalink to &quot;🗞️ 5 條今日黃金相關新聞&quot;">​</a></h2><h3 id="新聞-1-金價跌至-4-571-面臨技術修正" tabindex="-1">新聞 1：金價跌至 $4,571，面臨技術修正 <a class="header-anchor" href="#新聞-1-金價跌至-4-571-面臨技術修正" aria-label="Permalink to &quot;新聞 1：金價跌至 $4,571，面臨技術修正&quot;">​</a></h3><p>5/1 黃金現貨跌至 <strong>$4,571.84/盎司</strong>（-$11.42，-1.10%）。本週走低，受油價驅動的通膨擔憂和不確定利率前景影響。$4,600 為關鍵支撐、$4,950 為阻力。年增仍達 <strong>41.13%</strong>。 <em>來源：web_search (TradingEconomics, DailyForex, LongForecast)</em></p><h3 id="新聞-2-多家投行上修-2026-年底金價預測" tabindex="-1">新聞 2：多家投行上修 2026 年底金價預測 <a class="header-anchor" href="#新聞-2-多家投行上修-2026-年底金價預測" aria-label="Permalink to &quot;新聞 2：多家投行上修 2026 年底金價預測&quot;">​</a></h3><p>UBS 上修目標至 <strong>$6,200</strong>（9 月前，潛力 $7,200）。J.P. Morgan Q4 均價 <strong>$5,055</strong>，年底目標 <strong>$5,400</strong>。Goldman Sachs <strong>$5,400</strong>。Deutsche Bank 預測 5 年內可能觸及 <strong>$8,000</strong>。分析師共識：結構性多頭市場。 <em>來源：web_search (UBS, JPMorgan, Investing.com, GoldRepublic)</em></p><h3 id="新聞-3-央行-q1-購金-244-噸-波蘭、烏茲別克、中國領跑" tabindex="-1">新聞 3：央行 Q1 購金 244 噸，波蘭、烏茲別克、中國領跑 <a class="header-anchor" href="#新聞-3-央行-q1-購金-244-噸-波蘭、烏茲別克、中國領跑" aria-label="Permalink to &quot;新聞 3：央行 Q1 購金 244 噸，波蘭、烏茲別克、中國領跑&quot;">​</a></h3><p>WGC 公布 Q1 央行淨購金 <strong>244 噸</strong>（季增，高於五年平均）。主要買家：波蘭（20.23 噸）、烏茲別克（16.48 噸）、中國（2.18 噸）。俄羅斯（-15.55 噸）和土耳其（-8.08 噸）為淨賣家。去美元化趨勢持續推動從「西方到東方」的儲備轉移。 <em>來源：web_search (WGC, VisualCapitalist, GoldSilver)</em></p><h3 id="新聞-4-印度採購避險支撐金價" tabindex="-1">新聞 4：印度採購避險支撐金價 <a class="header-anchor" href="#新聞-4-印度採購避險支撐金價" aria-label="Permalink to &quot;新聞 4：印度採購避險支撐金價&quot;">​</a></h3><p>印度 5/1 黃金價格因川普對伊朗石油業的警告而出現避險買盤反彈，24K 金達 ₹15,250/克。印度 RBI 黃金儲備 880.52 噸，國內存放比例從 59.2% 大幅升至 77.23%，價值 $1,135 億。 <em>來源：web_search (Indian Express, GoodReturns, WGC)</em></p><h3 id="新聞-5-wgc-提出-2026-三種金價情境" tabindex="-1">新聞 5：WGC 提出 2026 三種金價情境 <a class="header-anchor" href="#新聞-5-wgc-提出-2026-三種金價情境" aria-label="Permalink to &quot;新聞 5：WGC 提出 2026 三種金價情境&quot;">​</a></h3><p>WGC 情境分析：① 溫和經濟降溫 → +5-15% ② 全球衰退+地緣衝擊 → +15-30%（可能突破 $6,500）③ 強勁成長+強美元+高利率 → <strong>-5% 至 -20%</strong>。目前環境最接近情境 ① 偏 ②，衰退擔憂與油價推升避險需求。 <em>來源：web_search (WGC Gold Demand Trends Q1 2026)</em></p><hr><h2 id="📋-10-項追蹤指標檢查結果" tabindex="-1">📋 10 項追蹤指標檢查結果 <a class="header-anchor" href="#📋-10-項追蹤指標檢查結果" aria-label="Permalink to &quot;📋 10 項追蹤指標檢查結果&quot;">​</a></h2><h3 id="✅-指標-1-comex-黃金現貨價格" tabindex="-1">✅ 指標 1：COMEX 黃金現貨價格 <a class="header-anchor" href="#✅-指標-1-comex-黃金現貨價格" aria-label="Permalink to &quot;✅ 指標 1：COMEX 黃金現貨價格&quot;">​</a></h3><p><strong>狀態：有變化 🟡 $4,571.84，週線下跌</strong></p><ul><li>5/1：<strong>$4,571.84/盎司</strong>（-$11.42，-1.10%）</li><li>52 週高點：$5,645.6（1/28 歷史新高）</li><li>年增率：<strong>+41.13%</strong></li><li>5 月均價預測：$4,582（LongForecast） <em>來源：web_search (TradingEconomics, LongForecast)</em></li></ul><h3 id="✅-指標-2-美國-10-年期-tips-實質利率" tabindex="-1">✅ 指標 2：美國 10 年期 TIPS 實質利率 <a class="header-anchor" href="#✅-指標-2-美國-10-年期-tips-實質利率" aria-label="Permalink to &quot;✅ 指標 2：美國 10 年期 TIPS 實質利率&quot;">​</a></h3><p><strong>狀態：維持高檔 🟡</strong></p><ul><li>10 年期 TIPS <strong>1.96%</strong>（為 2026 年以來高檔）</li><li>5 年期 1.34%，30 年期 2.71%</li><li>高實質利率為金價主要逆風 <em>來源：web_search (StreetStats)</em></li></ul><h3 id="✅-指標-3-美元指數-dxy" tabindex="-1">✅ 指標 3：美元指數 DXY <a class="header-anchor" href="#✅-指標-3-美元指數-dxy" aria-label="Permalink to &quot;✅ 指標 3：美元指數 DXY&quot;">​</a></h3><p><strong>狀態：有變化 🟢 月跌 1.88%</strong></p><ul><li>5/1 DXY <strong>98.15</strong>，月跌 <strong>1.88%</strong></li><li>美元走弱支撐金價，但實質利率高檔形成拉鋸 <em>來源：web_search (TradingView, FXStreet)</em></li></ul><h3 id="✅-指標-4-聯準會利率決策-點陣圖" tabindex="-1">✅ 指標 4：聯準會利率決策 + 點陣圖 <a class="header-anchor" href="#✅-指標-4-聯準會利率決策-點陣圖" aria-label="Permalink to &quot;✅ 指標 4：聯準會利率決策 + 點陣圖&quot;">​</a></h3><p><strong>狀態：無重大變化（距下次 FOMC 6 週）</strong></p><ul><li>4/29 綴持 <strong>3.5%-3.75%</strong></li><li>鮑爾最後一場會議出現罕見分歧，市場放棄今年降息押注</li><li>下次 FOMC 約 6 月中旬 <em>來源：web_search (CNA, 華爾街見聞)</em></li></ul><h3 id="✅-指標-5-央行購金數據-wgc-季報" tabindex="-1">✅ 指標 5：央行購金數據（WGC 季報） <a class="header-anchor" href="#✅-指標-5-央行購金數據-wgc-季報" aria-label="Permalink to &quot;✅ 指標 5：央行購金數據（WGC 季報）&quot;">​</a></h3><p><strong>狀態：有變化 🟢 Q1 購金 244 噸</strong></p><ul><li>Q1 淨購金 <strong>244 噸</strong>（高於五年平均）</li><li>買家：波蘭 20.23t、烏茲別克 16.48t、哈薩克 6.51t、中國 2.18t</li><li>賣家：俄羅斯 -15.55t、土耳其 -8.08t</li><li>去美元化趨勢是結構性支撐 <em>來源：web_search (WGC, VisualCapitalist)</em></li></ul><h3 id="✅-指標-6-地緣風險事件" tabindex="-1">✅ 指標 6：地緣風險事件 <a class="header-anchor" href="#✅-指標-6-地緣風險事件" aria-label="Permalink to &quot;✅ 指標 6：地緣風險事件&quot;">​</a></h3><p><strong>狀態：有變化 🔴 極端高風險</strong></p><ul><li>荷莫茲第 63 天封閉，伊朗領袖強硬表態</li><li>油價 $106-$111/桶推動通膨擔憂</li><li>印度 5/4 選舉結果預期波動</li><li>🚨 地緣避險為金價核心支撐 <em>來源：web_search (Al Jazeera, The Guardian)</em></li></ul><h3 id="✅-指標-7-通膨數據-cpi、pce" tabindex="-1">✅ 指標 7：通膨數據（CPI、PCE） <a class="header-anchor" href="#✅-指標-7-通膨數據-cpi、pce" aria-label="Permalink to &quot;✅ 指標 7：通膨數據（CPI、PCE）&quot;">​</a></h3><p><strong>狀態：無重大變化（距下次 CPI 2 週）</strong></p><ul><li>美國 3 月 CPI 3.3%，核心 CPI 低於 3%</li><li>油價 $111/桶推升能源通膨壓力</li><li>下次 CPI 約 5 月中旬公布 <em>來源：web_search (BLS)</em></li></ul><h3 id="✅-指標-8-黃金-etf-持倉量" tabindex="-1">✅ 指標 8：黃金 ETF 持倉量 <a class="header-anchor" href="#✅-指標-8-黃金-etf-持倉量" aria-label="Permalink to &quot;✅ 指標 8：黃金 ETF 持倉量&quot;">​</a></h3><p><strong>狀態：無重大變化</strong></p><ul><li>金價從 $5,589 高點回落至 $4,571（-18%），ETF 可能出現獲利了結</li><li>WGC 預測降息預期後退影響 ETF 流入 <em>來源：web_search (WGC)</em></li></ul><h3 id="✅-指標-9-黃金礦產供應" tabindex="-1">✅ 指標 9：黃金礦產供應 <a class="header-anchor" href="#✅-指標-9-黃金礦產供應" aria-label="Permalink to &quot;✅ 指標 9：黃金礦產供應&quot;">​</a></h3><p><strong>狀態：無重大變化（每季更新）</strong></p><ul><li>荷莫茲封閉不直接影響金礦供應（可空運）</li><li>全球年產約 3,600 噸，預估 2026 年小幅增加 <em>來源：web_search (WGC)</em></li></ul><h3 id="✅-指標-10-大型投行金價預測" tabindex="-1">✅ 指標 10：大型投行金價預測 <a class="header-anchor" href="#✅-指標-10-大型投行金價預測" aria-label="Permalink to &quot;✅ 指標 10：大型投行金價預測&quot;">​</a></h3><p><strong>狀態：有變化 🟢 多家上修目標</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">機構</th><th style="text-align:center;">2026 年底目標</th><th style="text-align:left;">來源</th></tr></thead><tbody><tr><td style="text-align:left;">UBS</td><td style="text-align:center;"><strong>$6,200</strong>（9 月，潛力 $7,200）</td><td style="text-align:left;">web_search (Investing.com)</td></tr><tr><td style="text-align:left;">J.P. Morgan</td><td style="text-align:center;"><strong>$5,055-$5,400</strong>（Q4）</td><td style="text-align:left;">web_search (JPMorgan)</td></tr><tr><td style="text-align:left;">Goldman Sachs</td><td style="text-align:center;"><strong>$5,400</strong></td><td style="text-align:left;">web_search (Goldman Sachs)</td></tr><tr><td style="text-align:left;">RBC Capital</td><td style="text-align:center;"><strong>$5,723</strong></td><td style="text-align:left;">web_search (GoldSilver)</td></tr><tr><td style="text-align:left;">Deutsche Bank</td><td style="text-align:center;"><strong>$8,000</strong>（5 年內）</td><td style="text-align:left;">web_search (InvestingLive)</td></tr></tbody></table><p><em>共識：結構性看多，潛在漲幅 25-40%</em><em>來源：web_search (UBS, JPMorgan, GoldSilver, InvestingLive)</em></p><hr><h2 id="📊-綜合評估" tabindex="-1">📊 綜合評估 <a class="header-anchor" href="#📊-綜合評估" aria-label="Permalink to &quot;📊 綜合評估&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">#</th><th style="text-align:left;">指標</th><th style="text-align:center;">狀態</th><th style="text-align:center;">方向</th><th style="text-align:left;">來源</th></tr></thead><tbody><tr><td style="text-align:center;">1</td><td style="text-align:left;">COMEX 現貨 $4,571.84</td><td style="text-align:center;">🟡 技術修正</td><td style="text-align:center;">偏空</td><td style="text-align:left;">TradingEconomics</td></tr><tr><td style="text-align:center;">2</td><td style="text-align:left;">TIPS 1.96%</td><td style="text-align:center;">🟡 高檔</td><td style="text-align:center;">利空</td><td style="text-align:left;">StreetStats</td></tr><tr><td style="text-align:center;">3</td><td style="text-align:left;">DXY 98.15（月跌 1.88%）</td><td style="text-align:center;">🟢 美元走弱</td><td style="text-align:center;">利多</td><td style="text-align:left;">TradingView</td></tr><tr><td style="text-align:center;">4</td><td style="text-align:left;">聯準會 3.5%-3.75%</td><td style="text-align:center;">無變化</td><td style="text-align:center;">中性</td><td style="text-align:left;">Fed.gov</td></tr><tr><td style="text-align:center;">5</td><td style="text-align:left;">央行 Q1 購金 244 噸</td><td style="text-align:center;">🟢 持續</td><td style="text-align:center;">利多</td><td style="text-align:left;">WGC</td></tr><tr><td style="text-align:center;">6</td><td style="text-align:left;">荷莫茲第 63 天</td><td style="text-align:center;">🔴 極端風險</td><td style="text-align:center;">利多</td><td style="text-align:left;">Al Jazeera</td></tr><tr><td style="text-align:center;">7</td><td style="text-align:left;">CPI 3.3%</td><td style="text-align:center;">無變化</td><td style="text-align:center;">偏空</td><td style="text-align:left;">BLS</td></tr><tr><td style="text-align:center;">8</td><td style="text-align:left;">ETF 持倉</td><td style="text-align:center;">無變化</td><td style="text-align:center;">中性</td><td style="text-align:left;">WGC</td></tr><tr><td style="text-align:center;">9</td><td style="text-align:left;">礦產供應</td><td style="text-align:center;">無變化</td><td style="text-align:center;">中性</td><td style="text-align:left;">WGC</td></tr><tr><td style="text-align:center;">10</td><td style="text-align:left;">投行目標 $5,400-$8,000</td><td style="text-align:center;">🟢 上修</td><td style="text-align:center;">利多</td><td style="text-align:left;">UBS, JPM, GS</td></tr></tbody></table><p><strong>多空平衡：偏多（央行購金 + 地緣風險 + 美元走弱 + 投行上修 vs 高實質利率 + 通膨壓力）</strong></p><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>web_search: 金價 $4,571.84 + 技術分析 | TradingEconomics, DailyForex, LongForecast</li><li>web_search: 投行上修目標（UBS $6,200, JPM $5,400, GS $5,400） | UBS, JPMorgan, GoldSilver</li><li>web_search: 央行 Q1 購金 244 噸 | WGC, VisualCapitalist, GoldSilver</li><li>web_search: 印度金價避險反彈 | Indian Express, GoodReturns</li><li>web_search: WGC 三種情境 | WGC Gold Demand Trends Q1 2026</li><li>web_search: 荷莫茲第 63 天 | Wikipedia, The Guardian</li><li>web_search: DXY 98.15 月跌 1.88% | FXStreet, TradingView</li><li>web_search: 聯準會維持利率 3.5%-3.75% | CNA, 華爾街見聞</li><li>web_search: TIPS 1.96% | StreetStats</li><li>web_search: 油價 $106-$111 | fxleaders, Economictimes</li></ol><hr><p><em>報告產出：Dr.32 知識管家 | 模型：local/Qwen3.6-35B-A3B-4bit</em></p>',56)])])}const b=e(n,[["render",i]]);export{x as __pageData,b as default};
